var allEvents = studio.project.model.Event.findInstances();
var standalone = [];
var preset = [];
var none = [];

function checkChain(chain, isPreset) {
  if (!chain || !chain.effects) return null;
  for (var i = 0; i < chain.effects.length; i++) {
    var e = chain.effects[i];
    if (!e) continue;
    if (e.entity === "SpatialiserEffect" || e.entity === "ObjectSpatialiserEffect")
      return isPreset ? "preset" : "standalone";
    if (e.entity === "ProxyEffect" && e.preset && e.preset.effect)
      return checkChain(e.preset.effect, true);
  }
  return null;
}

for (var i = 0; i < allEvents.length; i++) {
  var ev = allEvents[i];
  if (ev.banks.length === 0) continue;
  var ec = ev.masterTrack && ev.masterTrack.mixerGroup ? ev.masterTrack.mixerGroup.effectChain : null;
  if (!ec) continue;
  var r = checkChain(ec, false);
  if (r === "standalone") standalone.push(ev.getPath());
  else if (r === "preset") preset.push(ev.getPath());
  else none.push(ev.getPath());
}

return { standalone: standalone.length, preset: preset.length, none: none.length, total: standalone.length + preset.length + none.length };

