(function() {
  var reverbName = "Reverb";
  var eqTypes = ["ThreeEQEffect","ParamEqEffect","MultibandEqEffect","HighpassEffect","LowpassEffect"];
  function trackSendsToReverbNoEq(track) {
    var current = track.mixerGroup;
    var seen = {};
    while (current && !seen[current.id]) {
      seen[current.id] = true;
      var ec = current.effectChain;
      if (ec && ec.effects) {
        for (var i = 0; i < ec.effects.length; i++) {
          var e = ec.effects[i];
          if (e.mixerReturn && e.mixerReturn.name === reverbName) {
            var check = track.mixerGroup;
            var seen2 = {};
            while (check && !seen2[check.id]) {
              seen2[check.id] = true;
              var cec = check.effectChain;
              if (cec && cec.effects) {
                var limit = (check === current) ? i : cec.effects.length;
                for (var j = 0; j < limit; j++)
                  if (eqTypes.indexOf(cec.effects[j].entity) >= 0) return false;
              }
              if (check === current) break;
              check = check.output;
            }
            return true;
          }
        }
      }
      current = current.output;
    }
    return false;
  }
  var matching = [];
  var events = studio.project.model.Event.findInstances();
  for (var i = 0; i < events.length; i++) {
    var ev = events[i];
    if (ev.banks.length === 0) continue;
    for (var t = 0; t < (ev.groupTracks || []).length; t++) {
      if (trackSendsToReverbNoEq(ev.groupTracks[t])) {
        matching.push(ev.getPath ? ev.getPath() : ev.name);
        break;
      }
    }
  }
  matching.sort();
  return JSON.stringify(matching);
})();

// Refactor event: add Reverb return track with EQ (low down) before reverb send, route audio tracks to it, remove send from Master
(function() {
  var ev = studio.project.lookup("event:/Path/To/Event");
  var reverbReturnName = "Reverb";
  var reverbReturn = studio.project.model.MixerReturn.findInstances().filter(function(r){return r.name===reverbReturnName;})[0];
  var reverbTrack = ev.groupTracks.filter(function(t){ return t.mixerGroup.name === "Reverb"; })[0];
  if (!reverbTrack) reverbTrack = ev.addGroupTrack("Reverb");
  var master = ev.masterTrack.mixerGroup;
  var sendEffect = null, sendLevel = 0;
  for (var i = 0; i < master.effectChain.effects.length; i++) {
    if (master.effectChain.effects[i].mixerReturn && master.effectChain.effects[i].mixerReturn.id === reverbReturn.id) {
      sendEffect = master.effectChain.effects[i]; sendLevel = sendEffect.level; break;
    }
  }
  var eq = studio.project.create("ThreeEQEffect"); eq.lowGain = -80;
  var eqPreset = studio.project.create("EffectPreset"); eqPreset.effect = eq; eqPreset.name = "Low Cut";
  var send = studio.project.create("MixerSend"); send.mixerReturn = reverbReturn; send.level = sendLevel;
  var sendPreset = studio.project.create("EffectPreset"); sendPreset.effect = send; sendPreset.name = "Reverb Send";
  reverbTrack.mixerGroup.effectChain.addEffect(eqPreset);
  reverbTrack.mixerGroup.effectChain.addEffect(sendPreset);
  for (var i = 0; i < ev.groupTracks.length; i++) {
    var t = ev.groupTracks[i];
    if (t !== reverbTrack && t.mixerGroup.output && t.mixerGroup.output.name === "Master")
      t.mixerGroup.output = reverbTrack.mixerGroup;
  }
  for (var i = 0; i < master.effectChain.effects.length; i++) {
    if (master.effectChain.effects[i].mixerReturn && master.effectChain.effects[i].mixerReturn.id === reverbReturn.id) {
      master.effectChain.effects.splice(i, 1); break;
    }
  }
  studio.project.save();
})();

