// Find all looping events without instance limits (stealing mode = "None" or max instances = -1/infinite)
var events = studio.project.model.Event.findInstances();
var results = [];
var noLimitCount = 0;

for (var i = 0; i < events.length; i++) {
    var ev = events[i];
    if (!ev.isValid) continue;

    // Check if event is a loop by looking at loop regions or timeline loop properties
    // Also check instance limiting
    var isLoop = false;

    // Check instruments for looping
    try {
        var instruments = ev.findInstances("SingleSound");
        for (var j = 0; j < instruments.length; j++) {
            var inst = instruments[j];
            if (inst.isValid && inst.looping) {
                isLoop = true;
                break;
            }
        }
    } catch(e) {}

    // Also check for loop regions on the timeline
    if (!isLoop) {
        try {
            var loopRegions = ev.findInstances("LoopRegion");
            if (loopRegions && loopRegions.length > 0) {
                isLoop = true;
            }
        } catch(e) {}
    }

    if (isLoop) {
        // Check instance limiting: isPureEvent means no stealing/limiting
        var maxInstances = ev.maxInstances;
        var stealing = ev.instanceStealing;

        if (maxInstances <= 0) {
            noLimitCount++;
            results.push({
                path: ev.getPath(),
                maxInstances: maxInstances,
                stealing: stealing
            });
        }
    }
}

return JSON.stringify({ totalLoopingEventsWithNoLimit: noLimitCount, events: results });

// Find distribution of maxVoices values across all events to understand what "unlimited" looks like
var events = studio.project.model.Event.findInstances();
var voiceCounts = {};
var totalEvents = 0;

for (var i = 0; i < events.length; i++) {
    var ev = events[i];
    if (!ev.isValid) continue;
    totalEvents++;
    var ap = ev.automatableProperties;
    var mv = ap.maxVoices;
    voiceCounts[mv] = (voiceCounts[mv] || 0) + 1;
}

// Sort by count descending
var sorted = [];
for (var key in voiceCounts) {
    sorted.push({ maxVoices: parseInt(key), count: voiceCounts[key] });
}
sorted.sort(function(a, b) { return b.count - a.count; });

return JSON.stringify({ totalEvents: totalEvents, distribution: sorted });

// Find looping events with no instance limit (maxVoices = 65 = default/unlimited)
var events = studio.project.model.Event.findInstances();
var loopRegions = studio.project.model.LoopRegion.findInstances();
var singleSounds = studio.project.model.SingleSound.findInstances();

// Build set of event IDs that contain loop regions
var loopEventIds = {};
for (var i = 0; i < loopRegions.length; i++) {
    var lr = loopRegions[i];
    if (!lr.isValid) continue;
    // Walk up to find the owning event
    var obj = lr;
    var safety = 0;
    while (obj && safety < 20) {
        if (obj.entity === "Event") {
            loopEventIds[obj.id] = true;
            break;
        }
        obj = obj.owner;
        safety++;
    }
}

// Also find events with looping SingleSounds
for (var i = 0; i < singleSounds.length; i++) {
    var ss = singleSounds[i];
    if (!ss.isValid || !ss.looping) continue;
    var obj = ss;
    var safety = 0;
    while (obj && safety < 20) {
        if (obj.entity === "Event") {
            loopEventIds[obj.id] = true;
            break;
        }
        obj = obj.owner;
        safety++;
    }
}

// Now filter: looping events with maxVoices = 65 (unlimited)
var results = [];
for (var i = 0; i < events.length; i++) {
    var ev = events[i];
    if (!ev.isValid) continue;
    if (!loopEventIds[ev.id]) continue;
    var ap = ev.automatableProperties;
    if (ap.maxVoices === 65) {
        results.push(ev.getPath());
    }
}
results.sort();

return JSON.stringify({ count: results.length, events: results });

// Use _filePath to correlate LoopRegions and looping SingleSounds to their events
// Each event's objects share the same XML file path containing the event GUID

// Step 1: Build set of event file paths that have loops
var loopFilePaths = {};

var loopRegions = studio.project.model.LoopRegion.findInstances();
for (var i = 0; i < loopRegions.length; i++) {
    if (loopRegions[i].isValid) {
        loopFilePaths[loopRegions[i]._filePath] = true;
    }
}

var singleSounds = studio.project.model.SingleSound.findInstances();
for (var i = 0; i < singleSounds.length; i++) {
    if (singleSounds[i].isValid && singleSounds[i].looping) {
        loopFilePaths[singleSounds[i]._filePath] = true;
    }
}

// Step 2: Find events matching those file paths with maxVoices = 65
var events = studio.project.model.Event.findInstances();
var unlimited = [];
var limited = [];

for (var i = 0; i < events.length; i++) {
    var ev = events[i];
    if (!ev.isValid) continue;
    if (!loopFilePaths[ev._filePath]) continue;

    var ap = ev.automatableProperties;
    if (ap.maxVoices >= 65) {
        unlimited.push(ev.getPath());
    } else {
        limited.push({ path: ev.getPath(), maxVoices: ap.maxVoices });
    }
}

unlimited.sort();

